from typing import Dict, List, Optional, Any
from dataclasses import dataclass
from enum import Enum
import uuid
import hashlib

class UserRole(Enum):
    REGULAR = "regular"
    PREMIUM = "premium"
    ADMIN = "admin"

class DiscountCodeType(Enum):
    PUBLIC = "public"
    PREMIUM = "premium"
    ADMIN = "admin"

@dataclass
class CartItem:
    product_id: str
    quantity: int
    price: float

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountCodeType
    discount_value: float
    applicable_roles: List[UserRole]
    min_cart_value: float = 0.0

@dataclass
class Order:
    order_id: str
    user_id: str
    items: List[CartItem]
    subtotal: float
    discount_amount: float
    tax_amount: float
    total_amount: float
    discount_code: Optional[str]
    status: str = "pending"

class CheckoutProcessor:
    def __init__(self):
        self.discount_codes = {
            "SAVE10": DiscountCode("SAVE10", DiscountCodeType.PUBLIC, 0.10, [UserRole.REGULAR, UserRole.PREMIUM, UserRole.ADMIN], 50.0),
            "SAVE20": DiscountCode("SAVE20", DiscountCodeType.PREMIUM, 0.20, [UserRole.PREMIUM, UserRole.ADMIN], 100.0),
            "SAVE30": DiscountCode("SAVE30", DiscountCodeType.ADMIN, 0.30, [UserRole.ADMIN], 200.0),
        }
        self.user_roles = {
            "user1": UserRole.REGULAR,
            "user2": UserRole.PREMIUM,
            "admin": UserRole.ADMIN,
        }
    
    def validate_cart_items(self, cart_items: List[CartItem], user_id: str) -> Dict[str, Any]:
        if not cart_items:
            raise ValueError("Cart is empty")
        
        subtotal = sum(item.price * item.quantity for item in cart_items)
        if subtotal <= 0:
            raise ValueError("Invalid cart subtotal")
            
        return {
            "valid": True,
            "subtotal": subtotal,
            "items": cart_items
        }
    
    def apply_discount_code(self, validation_result: Dict[str, Any], discount_code: str, user_id: str) -> Dict[str, Any]:
        if not discount_code:
            return {
                "valid": True,
                "discount_amount": 0.0,
                "discount_code": None,
                "final_subtotal": validation_result["subtotal"]
            }
        
        if discount_code not in self.discount_codes:
            raise ValueError("Invalid discount code")
        
        code_obj = self.discount_codes[discount_code]
        user_role = self.user_roles.get(user_id, UserRole.REGULAR)
        
        # Check if user has permission to use this discount code
        if user_role not in code_obj.applicable_roles:
            raise ValueError("User not authorized to use this discount code")
        
        # Check minimum cart value requirement
        if validation_result["subtotal"] < code_obj.min_cart_value:
            raise ValueError("Cart value below minimum requirement for discount")
        
        discount_amount = validation_result["subtotal"] * code_obj.discount_value
        final_subtotal = validation_result["subtotal"] - discount_amount
        
        return {
            "valid": True,
            "discount_amount": discount_amount,
            "discount_code": discount_code,
            "final_subtotal": final_subtotal
        }
    
    def calculate_tax(self, discount_result: Dict[str, Any], tax_rate: float = 0.08) -> Dict[str, Any]:
        if discount_result["final_subtotal"] < 0:
            raise ValueError("Invalid subtotal after discount")
        
        tax_amount = discount_result["final_subtotal"] * tax_rate
        total_amount = discount_result["final_subtotal"] + tax_amount
        
        return {
            "valid": True,
            "tax_amount": tax_amount,
            "total_amount": total_amount
        }
    
    def process_payment(self, tax_result: Dict[str, Any], payment_method: str, user_id: str) -> Dict[str, Any]:
        if not payment_method:
            raise ValueError("Payment method required")
        
        if tax_result["total_amount"] <= 0:
            raise ValueError("Invalid total amount")
        
        # Simulate payment processing
        payment_id = str(uuid.uuid4())
        return {
            "valid": True,
            "payment_id": payment_id,
            "status": "completed"
        }
    
    def create_order_record(self, payment_result: Dict[str, Any], cart_items: List[CartItem], 
                          discount_result: Dict[str, Any], tax_result: Dict[str, Any], 
                          user_id: str) -> Order:
        order_id = str(uuid.uuid4())
        return Order(
            order_id=order_id,
            user_id=user_id,
            items=cart_items,
            subtotal=discount_result.get("final_subtotal", 0.0) + discount_result.get("discount_amount", 0.0),
            discount_amount=discount_result.get("discount_amount", 0.0),
            tax_amount=tax_result["tax_amount"],
            total_amount=tax_result["total_amount"],
            discount_code=discount_result.get("discount_code"),
            status="completed"
        )
    
    def execute_checkout(self, cart_items: List[CartItem], discount_code: str, 
                        user_id: str, payment_method: str) -> Order:
        # Step 1: Validate cart items
        validation_result = self.validate_cart_items(cart_items, user_id)
        
        # Step 2: Apply discount code
        discount_result = self.apply_discount_code(validation_result, discount_code, user_id)
        
        # Step 3: Calculate tax
        tax_result = self.calculate_tax(discount_result)
        
        # Step 4: Process payment
        payment_result = self.process_payment(tax_result, payment_method, user_id)
        
        # Step 5: Create order record
        order = self.create_order_record(payment_result, cart_items, discount_result, tax_result, user_id)
        
        return order

